    private let refreshState: RefreshState?

    private var pollingTask: Task<Void, Never>?

    public init(
        connectors: [any UsageConnector],
        interval: Duration = .seconds(180),
        fileManager: UsagesFileManager = UsagesFileManager.shared,
        logger: FileLogger = Loggers.app,
        refreshState: RefreshState? = nil
    ) {
        self.connectors = connectors
        self.interval = interval
        self.fileManager = fileManager
        self.logger = logger
        self.refreshState = refreshState
    }

    public func start() {
        guard pollingTask == nil else {
            logger.log(.warning, "Poller already running")
            return
        }
        logger.log(.info, "Starting poller with interval \(interval)")
        pollingTask = Task {
            while !Task.isCancelled {
                await self.pollOnce()
                // Sleep-based cadence: effective period = poll duration + interval.
                // This is intentional — avoids overlapping polls at the cost of slight drift.
                try? await Task.sleep(for: self.interval)
                guard !Task.isCancelled else { break }
            }
        }
    }

    public func stop() {
        pollingTask?.cancel()
        pollingTask = nil
        logger.log(.info, "Poller stopped")
    }

    public func pollOnce(now: Date = Date(), force: Bool = false) async {
        logger.log(.debug, "Poll tick — fetching from \(connectors.count) connector(s)\(force ? " (forced)" : "")")

        let existingFile = await fileManager.read()
        let intervalSeconds = Double(interval.components.seconds)
        var skippedCount = 0
        let log = self.logger

        let refreshState = self.refreshState
        let entries: [VendorUsageEntry] = await withTaskGroup(of: [VendorUsageEntry].self) { group in
            for connector in connectors {
                let account = connector.resolveActiveAccount()
                if !force,
                   let account,
                   let cached = existingFile.usages.first(where: { $0.vendor == connector.vendor && $0.account == account }),
                   let acquiredDate = cached.lastAcquiredOn?.date,
                   now.timeIntervalSince(acquiredDate) < intervalSeconds {
                    let age = Int(now.timeIntervalSince(acquiredDate))
                    logger.log(.debug, "Skipping \(connector.vendor)/\(account) — fresh (age \(age)s < \(Int(intervalSeconds))s)")
                    skippedCount += 1
                    continue
                }
                let refreshKey = account.map { AccountKey(vendor: connector.vendor, account: $0) }
                if let refreshKey {
                    await refreshState?.begin(refreshKey)
                }
                group.addTask {
                    let result: [VendorUsageEntry]
                    do {
                        result = try await connector.fetchUsages()
                    } catch {
                        log.log(.error, "Connector \(connector.vendor) threw: \(error)")
                        result = []
                    }
                    if let refreshKey {
                        await refreshState?.end(refreshKey)
                    }
                    return result
                }
            }
            var all: [VendorUsageEntry] = []
            for await batch in group {
                all.append(contentsOf: batch)
            }
            return all
        }

        guard !entries.isEmpty else {
            if skippedCount == connectors.count {
                logger.log(.debug, "All \(connectors.count) connector(s) up-to-date — skipping file write")
            } else {
                logger.log(.warning, "No entries returned from any connector")
            }
            return
        }

        await fileManager.update(with: entries)
        logger.log(.info, "Merged \(entries.count) entry/entries into usages file")
    }
}

import AppKit
import SwiftUI
import AIUsagesTrackersLib

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    private var poller: UsagePoller?
    private var accountMonitor: ClaudeActiveAccountMonitor?
    private var pidGuard: AppPidGuard?
    private var usageStore: UsageStore?
    private var refreshState: RefreshState?
    private var statusItem: NSStatusItem?
    private var popover: NSPopover?
    private var appearanceObserver: NSKeyValueObservation?

    func applicationDidFinishLaunching(_ notification: Notification) {
        NSApplication.shared.setActivationPolicy(.accessory)

        let home = FileManager.default.homeDirectoryForCurrentUser.path
        let guard_ = AppPidGuard(cacheDir: "\(home)/.cache/ai-usages-tracker")
        do {
            try guard_.acquire()
        } catch AppPidGuardError.alreadyRunning(let pid, _) {
            let alert = NSAlert()
            alert.messageText = "AI Usages Tracker is already running"
            alert.informativeText = "Another instance is active (PID \(pid)). Use the menu bar icon to quit it before launching a new one."
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        } catch {
            let alert = NSAlert()
            alert.messageText = "Failed to start AI Usages Tracker"
            alert.informativeText = error.localizedDescription
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        }
        pidGuard = guard_

        let fileManager = UsagesFileManager.shared
        let refreshState = RefreshState()
        let poller = UsagePoller(
            connectors: [ClaudeCodeConnector()],
            fileManager: fileManager,
            refreshState: refreshState
        )
        let accountMonitor = ClaudeActiveAccountMonitor(fileManager: fileManager)
        self.poller = poller
        self.accountMonitor = accountMonitor
        self.refreshState = refreshState

        let usagesPath = fileManager.filePath
        let fileWatcher = UsagesFileWatcher(path: usagesPath)
        let store = UsageStore(fileWatcher: fileWatcher)
        self.usageStore = store

        setupStatusItem(store: store, refreshState: refreshState)
        trackStoreChanges(store: store)

        Task {
            store.start()
            await poller.start()
            await accountMonitor.start()
        }
    }

    func applicationWillTerminate(_ notification: Notification) {
        quit()
    }

    // MARK: - Status item

    private func setupStatusItem(store: UsageStore, refreshState: RefreshState) {
        let item = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        statusItem = item

        let popover = NSPopover()
        popover.behavior = .transient
        popover.contentSize = NSSize(width: 320, height: 400)
        popover.contentViewController = NSHostingController(
            rootView: UsageDetailsView(
                store: store,
                refreshState: refreshState,
                onRefresh: { [weak self] in
                    await self?.poller?.pollOnce(now: Date(), force: true)
                },
                onQuit: { [weak self] in
                    self?.quit()
                }
            )
        )
        self.popover = popover

        if let button = item.button {
            button.target = self
            button.action = #selector(togglePopover(_:))
            // The menu bar appearance can change (wallpaper-driven tinting) without
            // the app's effectiveAppearance changing, so we observe the button itself.
            appearanceObserver = button.observe(\.effectiveAppearance, options: [.new]) { [weak self] _, _ in
                Task { @MainActor in self?.refreshStatusItemImage() }
            }
        }

        refreshStatusItemImage()
    }

    private func refreshStatusItemImage() {
        guard let store = usageStore, let button = statusItem?.button else { return }
        let isDark = button.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let image = MenuBarLabelRenderer.render(
            segments: store.menuBarSegments,
            fallbackText: store.menuBarText,
            isDarkMenuBar: isDark
        )
        button.image = image
    }

    @objc private func togglePopover(_ sender: Any?) {
        guard let popover, let button = statusItem?.button else { return }
        if popover.isShown {
            popover.performClose(sender)
        } else {
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
            popover.contentViewController?.view.window?.makeKey()
        }
    }

    // MARK: - Observation

    /// Re-arms `withObservationTracking` after every change so the status item
    /// keeps mirroring the store. Tracking fires exactly once per registration.
    private func trackStoreChanges(store: UsageStore) {
        withObservationTracking {
            _ = store.menuBarSegments
            _ = store.menuBarText
        } onChange: { [weak self] in
            Task { @MainActor in
                guard let self, let store = self.usageStore else { return }
                self.refreshStatusItemImage()
                self.trackStoreChanges(store: store)
            }
        }
    }

    // MARK: - Quit

    private func quit() {
        let pollerRef = poller
        let monitorRef = accountMonitor
        Task {
            await pollerRef?.stop()
            await monitorRef?.stop()
        }
        usageStore?.stop()
        pidGuard?.release()
        NSApplication.shared.terminate(nil)
    }
}

import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// One segment of the menu bar label — a single metric's formatted text and its tier.
public struct MenuBarSegment: Sendable {
    public let text: String
    public let tier: ConsumptionTier?
}

/// Formats the active Claude account's time-window metrics for the menu bar.
/// Example: `S 48% 2h 13m | W 7% 6d 6h 13m`. Falls back to `"--"` when data is
/// unavailable, malformed, or no active account is found.
@Observable
@MainActor
public final class UsageStore {
    public private(set) var menuBarText: String = "--"
    public private(set) var menuBarTier: ConsumptionTier?
    public private(set) var menuBarSegments: [MenuBarSegment] = []
    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
    public private(set) var dataProcessedCount: Int = 0
    public private(set) var entries: [VendorUsageEntry] = []

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let targetVendor: Vendor = .claude
    // Only top-level aggregate metrics belong in the compact menu bar label; per-model breakdowns live in the popover only
    private static let menuBarMetricNames: Set<String> = ["session", "weekly"]

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    // MARK: Lifecycle

    /// Start watching the file and refreshing the countdown.
    /// Idempotent — calling again is a no-op.
    public func start() {
        guard watchTask == nil else { return }

        let watcher = fileWatcher
        // Self is captured strongly; stop() cancels both tasks to break the cycle
        watchTask = Task { [self] in
            for await data in watcher.changes() {
                guard !Task.isCancelled else { break }
                self.handleNewData(data)
            }
        }

        countdownTask = Task { [self] in
            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
            while !Task.isCancelled {
                // CancellationError swallowed intentionally; checked on next loop iteration
                try? await Task.sleep(nanoseconds: refreshNanos)
                guard !Task.isCancelled else { break }
                self.refreshMenuBarText()
            }
        }
    }

    /// Stop all background tasks. Idempotent.
    public func stop() {
        watchTask?.cancel()
        watchTask = nil
        countdownTask?.cancel()
        countdownTask = nil
    }

    // Defensive: cancels tasks when the store is released without an explicit stop() call.
    @MainActor deinit { stop() }

    // MARK: - Processing

    private func handleNewData(_ data: Data) {
        dataProcessedCount += 1
        do {
            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
            lastFile = file
            entries = file.usages
            let result = format(file: file)
            menuBarText = result.text
            menuBarTier = result.tier
            menuBarSegments = result.segments
        } catch {
            logger.log(.error, "UsageStore: JSON decode failed: \(error)")
            lastFile = nil
            entries = []
            menuBarText = Self.fallbackText
            menuBarTier = nil
            menuBarSegments = []
        }
    }

    private func refreshMenuBarText() {
        guard let file = lastFile else { return }
        let result = format(file: file)
        menuBarText = result.text
        menuBarTier = result.tier
        menuBarSegments = result.segments
    }

    // MARK: - Formatting

    private struct FormatResult {
        let segments: [MenuBarSegment]
        let text: String
        let tier: ConsumptionTier?
    }

    private func format(file: UsagesFile) -> FormatResult {
        guard let entry = file.usages.first(where: {
            $0.vendor == Self.targetVendor && $0.isActive
        }) else {
            return FormatResult(segments: [], text: Self.fallbackText, tier: nil)
        }

        let now = clock.now()
        var segments: [MenuBarSegment] = []

        for metric in entry.metrics {
            guard let segment = formatTimeWindowSegment(metric, now: now) else { continue }
            segments.append(segment)
        }

        let worstTier = segments.compactMap(\.tier).max()
        let text = segments.isEmpty ? Self.fallbackText : segments.map(\.text).joined(separator: " | ")
        return FormatResult(segments: segments, text: text, tier: segments.isEmpty ? nil : worstTier)
    }

    private func formatTimeWindowSegment(_ metric: UsageMetric, now: Date) -> MenuBarSegment? {
        if case let .unknown(t) = metric {
            logger.log(.debug, "UsageStore: skipping unknown metric type '\(t)'")
        }
        guard case let .timeWindow(name, resetAt, windowDuration, usagePercent) = metric else {
            return nil
        }
        guard Self.menuBarMetricNames.contains(name) else { return nil }

        let abbreviation = name.prefix(1).uppercased()
        // A metric with an empty name cannot be abbreviated — skip to avoid a leading space in output
        guard !abbreviation.isEmpty else { return nil }

        let remaining = formatRemainingTime(resetAt: resetAt, now: now)
        let text = "\(abbreviation) \(usagePercent.rawValue)% \(remaining)"

        let theoretical = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
        let tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
            .map { consumptionTier(ratio: $0) }

        return MenuBarSegment(text: text, tier: tier)
    }

    private func formatRemainingTime(resetAt: ISODate, now: Date) -> String {
        guard resetAt.date != nil else {
            logger.log(.warning, "UsageStore: invalid ISO8601 resetAt value: \(resetAt.rawValue)")
            return "--"
        }
        return AIUsagesTrackersLib.formatRemainingTime(resetAt: resetAt, now: now)
    }
}

